import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.BYlK8ftn.js";const g=JSON.parse('{"title":"Korovany — Game Development Plan","description":"","frontmatter":{},"headers":[],"relativePath":"plan/game-plan.md","filePath":"plan/game-plan.md","lastUpdated":1781972202000}'),n={name:"plan/game-plan.md"};function r(i,e,l,c,d,p){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="korovany-—-game-development-plan" tabindex="-1">Korovany — Game Development Plan <a class="header-anchor" href="#korovany-—-game-development-plan" aria-label="Permalink to &quot;Korovany — Game Development Plan&quot;">​</a></h1><blockquote><p>Canonical design source: <a href="https://github.com/Flopsstuff/korovany/issues/2" target="_blank" rel="noreferrer">Flopsstuff/korovany#2</a> (the original &quot;корованы&quot; brief from Kirill). Coordination issue: <strong>FLO-273</strong>. This document is the <strong>living plan</strong>. It is updated as the tree grows — every new epic/task references the phase it belongs to. Plan revisions are gated for board approval before implementation subtasks are created.</p></blockquote><h2 id="_0-what-we-are-building-from-the-canonical-brief" tabindex="-1">0. What we are building (from the canonical brief) <a class="header-anchor" href="#_0-what-we-are-building-from-the-canonical-brief" aria-label="Permalink to &quot;0. What we are building (from the canonical brief)&quot;">​</a></h2><p>A browser, <strong>serverless</strong>, single-player (+ NPC) <strong>3D action-RPG</strong>. The player can play as one of three factions and roam a world of <strong>four zones</strong>:</p><table tabindex="0"><thead><tr><th>#</th><th>Zone</th><th>Owner</th><th>Notes</th></tr></thead><tbody><tr><td>1</td><td>Human lands</td><td>Neutral</td><td>trade, towns</td></tr><tr><td>2</td><td>Empire</td><td>Emperor</td><td>the <strong>palace</strong> to attack/defend</td></tr><tr><td>3</td><td>Forest</td><td><strong>Forest Elves</strong></td><td>dense forest, wooden huts</td></tr><tr><td>4</td><td>Mountains</td><td><strong>The Villain</strong></td><td>an old fort</td></tr></tbody></table><p>Signature features from the brief, mapped to where they live in this plan:</p><ul><li><strong>Three playable factions</strong> with asymmetric goals (Elves raid; Palace Guard obeys a commander &amp; defends; Villain commands their own troops). → Phase 4</li><li><strong>Rob the caravans</strong> (&quot;грабить корованы&quot;) — the signature loot loop. → Phase 3</li><li><strong>Dense forest with LOD</strong>: distant trees as billboards/impostors that resolve into full 3D as you approach. → Phase 5</li><li><strong>Daggerfall-like RPG layer</strong>: shops, buying, character progression. → Phase 4</li><li><strong>Combat</strong>: melee, jumping, 3D enemies, <strong>3D corpses</strong>. → Phase 2</li><li><strong>Injury / dismemberment</strong>: lose a hand → bleed out if untreated; lose an eye → half-screen blackout (or prosthetic); lose a leg → die / crawl / wheelchair / prosthetic; healing. → Phase 2 (model) + Phase 6 (full prosthetic economy)</li><li><strong>Browser saves</strong>. → Phase 1</li></ul><blockquote><p>&quot;Я джва года хочу такую игру.&quot; We respect the ambition by shipping a <strong>playable vertical slice early</strong> and growing the tree toward the full vision, rather than attempting the whole myth at once.</p></blockquote><h2 id="_1-engineering-principles-for-this-plan" tabindex="-1">1. Engineering principles for this plan <a class="header-anchor" href="#_1-engineering-principles-for-this-plan" aria-label="Permalink to &quot;1. Engineering principles for this plan&quot;">​</a></h2><ul><li><strong>Vertical slice first.</strong> Phase 1 proves the entire stack (full-page render, controller, streaming, save/load) with one faction in one zone. Every later phase widens, it does not re-architect.</li><li><strong>Serverless, browser-only.</strong> No backend, ever. Saves use <strong>IndexedDB</strong>; assets stream from static hosting (Cloudflare Pages + Git LFS, per <a href="./../decisions/0001-asset-hosting">ADR-0001</a>).</li><li><strong>Dynamic asset loading is a first-class system</strong>, not an afterthought — the brief demands streaming forests and zones. Built in Phase 1, exploited in 5.</li><li><strong>Small, oneshot tasks.</strong> Each ticket is sized for ~one commit / one MR with a testable acceptance criterion. Big features become epics (child issues) whose children are the oneshots.</li><li><strong>Tests + docs in the same change</strong> (AGENTS.md golden rules). No exceptions.</li><li><strong>Boring tech a maintainer can debug at 2am.</strong> Babylon&#39;s built-in systems (camera, physics, GLB import, instancing/LOD) before any bespoke engine code.</li><li><strong>Assets are generated per concrete character ticket only</strong> — never speculatively (board directive FLO-270). Low-poly visual language v1.2 (≤3000 tris/object) is binding; see the visual-language doc.</li></ul><h2 id="_2-system-architecture-target" tabindex="-1">2. System architecture (target) <a class="header-anchor" href="#_2-system-architecture-target" aria-label="Permalink to &quot;2. System architecture (target)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── app/            App shell: routes menu ↔ game, mounts HUD over canvas</span></span>
<span class="line"><span>├── scenes/         Babylon worlds — one GameScene that hosts the active zone</span></span>
<span class="line"><span>├── game/           Engine-agnostic systems &amp; rules (the bulk of gameplay):</span></span>
<span class="line"><span>│   ├── loop/         fixed-step update loop, system scheduler</span></span>
<span class="line"><span>│   ├── input/        keyboard/mouse/pointer-lock → intent</span></span>
<span class="line"><span>│   ├── controller/   character movement, jump, collision</span></span>
<span class="line"><span>│   ├── camera/       third-person follow rig</span></span>
<span class="line"><span>│   ├── streaming/    asset registry, lazy GLB loading, LOD/impostors</span></span>
<span class="line"><span>│   ├── combat/       melee, hit detection, damage</span></span>
<span class="line"><span>│   ├── health/       hit points, injuries, dismemberment, healing</span></span>
<span class="line"><span>│   ├── ai/           NPC behaviour (patrol/chase/attack/flee)</span></span>
<span class="line"><span>│   ├── world/        zones, terrain, spawn tables, caravans</span></span>
<span class="line"><span>│   ├── faction/      faction definitions, objectives, command</span></span>
<span class="line"><span>│   ├── economy/      currency, shops, inventory</span></span>
<span class="line"><span>│   └── save/         IndexedDB serialize/restore, save slots</span></span>
<span class="line"><span>├── components/     React HUD (health, minimap, inventory, dialogs)</span></span>
<span class="line"><span>├── store/          Redux slices bridging game state ↔ HUD</span></span>
<span class="line"><span>└── types/          shared domain types</span></span></code></pre></div><p>Data flow stays as today: Babylon owns the render loop and writes salient state into Redux; React HUD reads via typed selectors. Pure game logic in <code>src/game/</code> has <strong>no</strong> React/Babylon imports where avoidable, so it is unit-testable in jsdom.</p><h2 id="_3-the-plan-tree-phases-→-epics-→-sample-tasks" tabindex="-1">3. The plan tree (phases → epics → sample tasks) <a class="header-anchor" href="#_3-the-plan-tree-phases-→-epics-→-sample-tasks" aria-label="Permalink to &quot;3. The plan tree (phases → epics → sample tasks)&quot;">​</a></h2><p>Legend: <code>[ ]</code> not started · <code>[~]</code> in progress · <code>[x]</code> done. Each epic becomes a <strong>child issue of FLO-273</strong>; each task a child of its epic.</p><h3 id="phase-0-—-foundation-cleanup-unblocks-everything-x" tabindex="-1">Phase 0 — Foundation cleanup (unblocks everything) <code>[x]</code> <a class="header-anchor" href="#phase-0-—-foundation-cleanup-unblocks-everything-x" aria-label="Permalink to &quot;Phase 0 — Foundation cleanup (unblocks everything) \`[x]\`&quot;">​</a></h3><p>Epic: <strong><a href="/korovany/FLO/issues/FLO-277">FLO-277</a></strong> — board plan approved 2026-06-20.</p><blockquote><p><strong>Done &amp; merged to <code>main</code> 2026-06-20.</strong> The full-page canvas, fixed-step loop, and input system are live on korovany.aimost.pl. Concurrent runs produced duplicate tickets (FLO-281/282/284/285) which were reconciled/cancelled; the canonical merged PRs are below.</p></blockquote><ul><li><strong>E0.1 Full-page canvas &amp; app shell</strong> <code>[x]</code> — FLO-280 (PR #4), FLO-283 (PR #7) <ul><li>[x] Make the Babylon canvas fill the viewport (replace fixed 320px); handle resize/DPR.</li><li>[ ] App state machine: <code>menu → playing → paused</code>; ESC toggles pause. <em>(carried into E1.0)</em></li><li>[ ] Main menu shell (New Game / Continue / Settings) as a React overlay. <em>(carried into E1.0)</em></li></ul></li><li><strong>E0.2 Game loop &amp; system scheduler</strong> <code>[x]</code> — FLO-278 (PR #5) <ul><li>[x] Fixed-step update loop in <code>src/game/loop/</code> decoupled from render FPS; unit-tested.</li><li>[x] System registration API (systems get <code>update(dt, world)</code>).</li></ul></li><li><strong>E0.3 Input system</strong> <code>[x]</code> — FLO-279 (PR #3) <ul><li>[x] Keyboard/mouse intent mapping; pointer-lock for mouselook; rebindable map (data-driven).</li></ul></li></ul><h3 id="phase-1-—-vertical-slice-an-elf-in-the-forest" tabindex="-1">Phase 1 — Vertical slice: &quot;An elf in the forest&quot; <code>[~]</code> <a class="header-anchor" href="#phase-1-—-vertical-slice-an-elf-in-the-forest" aria-label="Permalink to &quot;Phase 1 — Vertical slice: &quot;An elf in the forest&quot; \`[~]\`&quot;">​</a></h3><p>Goal: a deployed build where you start a new game, spawn as an elf in a small forest, walk/run/jump with a third-person camera over solid ground, and your position+health survive a reload (browser save). Proves the whole stack.</p><p>Epic: <strong><a href="/korovany/FLO/issues/FLO-291">FLO-291</a></strong> — decomposed into canonical oneshot tickets 2026-06-20 (one MR each). <strong>Check these before cutting any new Phase-1 child</strong> (Phase 0 was built 3× by concurrent runs). Blocker DAG: E1.2→E1.3, E1.1→E1.4, and {E1.0,E1.1,E1.3,E1.4}→E1.5.</p><ul><li><strong>E1.0 App state machine &amp; menu shell</strong> <code>[x]</code> — FLO-292 (Aldric) ✅ merged 82788cd <em>(carried from E0.1)</em><ul><li>[x] <code>menu → playing → paused</code> state machine; ESC toggles pause.</li><li>[x] Main menu shell (New Game / Continue / Settings) as a React overlay over the canvas.</li></ul></li><li><strong>E1.1 Third-person character controller</strong> <code>[ ]</code> — FLO-293 (Wayland) <ul><li>[ ] Capsule controller: WASD move, sprint, gravity, ground collision.</li><li>[ ] Jump with coyote-time; cannot double-jump.</li><li>[ ] Third-person follow camera with collision-aware boom.</li></ul></li><li><strong>E1.2 Asset streaming manager</strong> <code>[ ]</code> — FLO-294 (Soren) <ul><li>[ ] Asset registry (id → URL + metadata); <code>streaming/</code> loads GLB on demand, caches, disposes.</li><li>[ ] Loading state surfaced to HUD; graceful fallback placeholder while loading.</li></ul></li><li><strong>E1.3 First zone (forest stub)</strong> <code>[ ]</code> — FLO-295 (Lyra, blocked by FLO-294; <strong>needs assets FLO-299</strong>) <ul><li>[ ] Ground/terrain mesh for a small forest clearing with collision.</li><li>[ ] Scatter a handful of streamed tree + hut GLBs (static, no LOD yet).</li><li><em>Assets:</em> the tree + hut GLBs come from <strong>FLO-299</strong> (Pygmalion); they did not exist in the repo when Phase 1 was decomposed. Land FLO-299 before E1.3 starts.</li></ul></li><li><strong>E1.4 Save/load (IndexedDB)</strong> <code>[ ]</code> — FLO-296 (Wayland, blocked by FLO-293) <ul><li>[ ] Serialize player transform + health + zone id to IndexedDB; restore on Continue.</li><li>[ ] Save-slot UI (≥1 slot); autosave on pause.</li></ul></li><li><strong>E1.5 Deploy the slice</strong> <code>[ ]</code> — FLO-297 (Wayland, blocked by FLO-292/293/295/296) <ul><li>[ ] Wire GameScene into the app; ship to korovany.aimost.pl; smoke in a real browser.</li></ul></li></ul><h3 id="phase-2-—-combat-health-injuries" tabindex="-1">Phase 2 — Combat, health &amp; injuries <code>[ ]</code> <a class="header-anchor" href="#phase-2-—-combat-health-injuries" aria-label="Permalink to &quot;Phase 2 — Combat, health &amp; injuries \`[ ]\`&quot;">​</a></h3><ul><li><strong>E2.1 Health &amp; damage model</strong> <code>[ ]</code> — HP, damage events, death state, respawn/load.</li><li><strong>E2.2 Melee combat</strong> <code>[ ]</code> — attack animation window, hitbox sweep, damage to targets.</li><li><strong>E2.3 Enemy NPC (first archetype)</strong> <code>[ ]</code> — patrol → detect → chase → attack → die; one soldier model.</li><li><strong>E2.4 3D corpses</strong> <code>[ ]</code> — on death, leave a ragdoll/static corpse mesh that persists &amp; can be looted.</li><li><strong>E2.5 Injury &amp; dismemberment model</strong> <code>[ ]</code> — data model for limb/eye/leg states. <ul><li>[ ] Lose-a-hand → bleed timer → death if untreated; healing item stops it.</li><li>[ ] Lose-an-eye → half-screen vignette; prosthetic/eyepatch removes it.</li><li>[ ] Lose-a-leg → crawl/reduced-speed locomotion state.</li></ul></li></ul><h3 id="phase-3-—-world-caravans-loot-loop" tabindex="-1">Phase 3 — World, caravans &amp; loot loop <code>[ ]</code> <a class="header-anchor" href="#phase-3-—-world-caravans-loot-loop" aria-label="Permalink to &quot;Phase 3 — World, caravans &amp; loot loop \`[ ]\`&quot;">​</a></h3><ul><li><strong>E3.1 World map &amp; 4 zones</strong> <code>[ ]</code> — zone definitions, fast-travel/world map UI, per-zone streaming.</li><li><strong>E3.2 Zone streaming</strong> <code>[ ]</code> — load/unload zone content as the player crosses borders; budget memory.</li><li><strong>E3.3 Caravans (&quot;грабить корованы&quot;)</strong> <code>[ ]</code> — wandering caravan entities, ambush, loot tables, reward.</li><li><strong>E3.4 Inventory &amp; loot</strong> <code>[ ]</code> — pick up, carry, equip; HUD inventory panel.</li></ul><h3 id="phase-4-—-factions-economy-the-rpg-layer" tabindex="-1">Phase 4 — Factions &amp; economy (the RPG layer) <code>[ ]</code> <a class="header-anchor" href="#phase-4-—-factions-economy-the-rpg-layer" aria-label="Permalink to &quot;Phase 4 — Factions &amp; economy (the RPG layer) \`[ ]\`&quot;">​</a></h3><ul><li><strong>E4.1 Faction system</strong> <code>[ ]</code> — faction data, reputation, friend/foe targeting.</li><li><strong>E4.2 Faction selection &amp; asymmetric goals</strong> <code>[ ]</code><ul><li>[ ] Elf campaign: raid empire/villain, defend forest.</li><li>[ ] Palace Guard campaign: obey commander orders, defend palace.</li><li>[ ] Villain campaign: command own troops, order attacks on the palace.</li></ul></li><li><strong>E4.3 Commander / order system</strong> <code>[ ]</code> — issue/receive orders; squad follow &amp; attack.</li><li><strong>E4.4 Economy &amp; shops (Daggerfall-like)</strong> <code>[ ]</code> — currency, shop UI, buy/sell, prices.</li><li><strong>E4.5 Character progression</strong> <code>[ ]</code> — stats/skills that buying &amp; combat feed into.</li></ul><h3 id="phase-5-—-dense-forest-lod-streaming" tabindex="-1">Phase 5 — Dense forest &amp; LOD streaming <code>[ ]</code> <a class="header-anchor" href="#phase-5-—-dense-forest-lod-streaming" aria-label="Permalink to &quot;Phase 5 — Dense forest &amp; LOD streaming \`[ ]\`&quot;">​</a></h3><ul><li><strong>E5.1 Tree impostors</strong> <code>[ ]</code> — billboard/impostor distant trees.</li><li><strong>E5.2 Impostor→3D promotion</strong> <code>[ ]</code> — swap to full GLB within range; hysteresis to avoid popping.</li><li><strong>E5.3 Instanced vegetation</strong> <code>[ ]</code> — thin-instances for dense forest at frame budget.</li><li><strong>E5.4 Performance budget &amp; profiling</strong> <code>[ ]</code> — keep 60fps target on mid hardware; document budgets.</li></ul><h3 id="phase-6-—-depth-polish" tabindex="-1">Phase 6 — Depth &amp; polish <code>[ ]</code> <a class="header-anchor" href="#phase-6-—-depth-polish" aria-label="Permalink to &quot;Phase 6 — Depth &amp; polish \`[ ]\`&quot;">​</a></h3><ul><li><strong>E6.1 Prosthetics economy</strong> <code>[ ]</code> — buy/fit hand/leg/eye prosthetics; wheelchair locomotion.</li><li><strong>E6.2 Audio</strong> <code>[ ]</code> — footsteps, combat, ambience (streamed).</li><li><strong>E6.3 Quests / objectives</strong> <code>[ ]</code> — per-faction objective chains.</li><li><strong>E6.4 Settings &amp; accessibility</strong> <code>[ ]</code> — graphics quality, controls, key rebinding UI.</li><li><strong>E6.5 Menu, save management, polish pass</strong> <code>[ ]</code>.</li></ul><h2 id="_4-asset-roadmap-gated-per-character-only" tabindex="-1">4. Asset roadmap (gated, per-character only) <a class="header-anchor" href="#_4-asset-roadmap-gated-per-character-only" aria-label="Permalink to &quot;4. Asset roadmap (gated, per-character only)&quot;">​</a></h2><p>Models are generated <strong>only</strong> on concrete tickets, via the <code>tools/meshy-3d</code> pipeline, in low-poly visual language v1.2. Near-term needs, in slice order:</p><ol><li>Elf player character (Phase 1) — <em>already have a generic hero GLB; evaluate reuse first.</em> → decision folded into <strong>FLO-299</strong> (recommend reuse for the slice).</li><li>Forest tree + wooden hut (Phase 1) — <strong>FLO-299</strong> (Pygmalion), unblocks E1.3.</li><li>Empire soldier enemy (Phase 2).</li><li>Corpse variant (Phase 2).</li><li>Caravan + cargo (Phase 3).</li></ol><p>Each asset ticket cites the visual-language doc and the licensing terms; no speculative batches (FLO-270).</p><h2 id="_5-how-tasks-flow-delegation-contract" tabindex="-1">5. How tasks flow (delegation contract) <a class="header-anchor" href="#_5-how-tasks-flow-delegation-contract" aria-label="Permalink to &quot;5. How tasks flow (delegation contract)&quot;">​</a></h2><ol><li>The next-up <strong>epic</strong> is opened as a child of FLO-273 with acceptance criteria and its parent phase.</li><li>Each <strong>oneshot task</strong> under it is a child of the epic, assigned to <strong>Wayland</strong> (implementation) or <strong>Iris</strong> (UX) with: one clear deliverable, the branch name (<code>flo-&lt;n&gt;-&lt;slug&gt;</code> off <code>main</code>), acceptance criteria, tests+docs required.</li><li>The engineer opens <strong>one MR per task</strong>. CTO reviews (branch isolation, tests, docs, visual-truth gate for UI), then merges; <code>main</code> deploys.</li><li>As phases complete, this document is updated (checkboxes + new tasks) and the tree grows. New Sub-issues from Fl0p on #2 are triaged into the right phase.</li></ol><h2 id="_6-risks-how-the-plan-absorbs-them" tabindex="-1">6. Risks &amp; how the plan absorbs them <a class="header-anchor" href="#_6-risks-how-the-plan-absorbs-them" aria-label="Permalink to &quot;6. Risks &amp; how the plan absorbs them&quot;">​</a></h2><ul><li><strong>Scope is mythical.</strong> Mitigated by phasing: a playable, deployed slice exists from Phase 1; every later feature is additive, never a rewrite.</li><li><strong>Asset cost/time.</strong> Per-character gating + reuse-first keeps Meshy spend bounded.</li><li><strong>Browser performance with a dense forest.</strong> Deferred to Phase 5 behind LOD &amp; instancing, with an explicit frame budget; the slice ships with a sparse forest.</li><li><strong>Storage limits in the browser.</strong> IndexedDB save payloads stay small (state, not assets); assets always stream from static hosting.</li></ul><hr><p><em>Revision history</em></p><ul><li><strong>r1</strong> (2026-06-20) — initial plan tree authored by Daedalus (CTO) from canonical brief #2. Pending board approval before Phase 0/1 subtasks are cut.</li><li><strong>r2</strong> (2026-06-20) — board approved r1. Phase 0 epic [FLO-277] cut with its three oneshots: E0.1 app shell [FLO-280] (Wayland, started), E0.2 game loop [FLO-281] (Wayland, blocked by E0.1), E0.3 input [FLO-282] (Aldric, blocked by E0.1). Phase 0 marked in progress; menu/state-machine sub-items deferred to a follow-up so the slice path stays the critical line.</li><li><strong>r3</strong> (2026-06-20) — Phase 0 marked <strong>done &amp; merged to <code>main</code></strong> (canonical PRs: canvas FLO-280/#4, loop FLO-278/#5, input FLO-279/#3, shell-cleanup FLO-283/#7; duplicate tickets FLO-281/282/284/285 cancelled). Menu/pause state machine carried forward into new prelude epic <strong>E1.0</strong>. Phase 1 opened as the active epic and delegated to the CTO to decompose into oneshot tickets — closes the post-Phase-0 coordination gap that stalled the tree (Prospero).</li><li><strong>r4</strong> (2026-06-20) — progress review (FLO-298). Phase 1 oneshots are in flight: E1.0 [FLO-292] (Aldric), E1.1 [FLO-293] (Wayland), E1.2 [FLO-294] (Soren) are <strong>in progress</strong>; E1.3/E1.4/E1.5 [FLO-295/296/297] correctly <strong>blocked</strong> by their DAG. Two gaps closed by new backlog tickets: <strong>FLO-299</strong> (Pygmalion) generates the missing forest tree + hut GLBs and resolves the elf-mesh reuse decision — a prerequisite for E1.3 that had no ticket; <strong>FLO-300</strong> (Wayland) adds the <code>npm run lint</code> gate to CI (<code>deploy.yml</code> ran only test+build). No PRs landed for Phase 1 yet. Phase 2 (combat/health) stays unticketed by design — its epic is opened only after the slice deploys (E1.5), per the just-in-time decomposition rule that kept Phase 0 from being built 3×.</li></ul>`,44)])])}const m=a(n,[["render",r]]);export{g as __pageData,m as default};
